var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"이상으로, 보고를 마치겠습니다.","JPN":"報告は以上です。","ENG":"That concludes my briefing.","TWN":"以上就是報告的全部內容。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"POLICE_NPC_CHIEF_NULL","text":{"KOREA":"좋아. 이제 조직도가 얼추 맞아떨어졌고, 놈들의 행동반경과 패턴도 어느 정도 파악됐으니……","JPN":"よし。組織図もそろそろ見えてきたし、やつらの行動半径とパータンもそれなりに把握できたから……","ENG":"All right. Looks like we got those perps all mapped out and what their daily schedule is like…","TWN":"很好。現在組織結構大致對上了，敵人的活動範圍和模式也已經掌握了…"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"POLICE_NPC_CHIEF_NULL","text":{"KOREA":"이제 기회를 봐서 일망타진하는 일만 남았군.","JPN":"あとは、機会を見て一網打尽するだけだな。","ENG":"Now, we just wait for the right timing to strike.","TWN":"現在就剩下找機會一網打盡了。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"네, 아시다시피 두 조직은 치안이 빈약한 빈민가에서 활동하기 때문에 아주 대범하게 움직이고 있습니다.","JPN":"はい。ご存じの通り、両組織は治安が悪いスラム街で活動しているため、とても大胆に動いています。","ENG":"As you know, the two families are stationed in the slums, and have been boldly active.","TWN":"是的，這兩個組織經常在治安較差的貧民區活動，所以行動非常大膽。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"게다가 지금은 양측 모두 얼마 전 도시에 나타난 위저드라는 신흥 세력을 견제하는 중입니다.","JPN":"それに今は両方とも、この前から都市に現われたウィザードという新興勢力を牽制しているところです。","ENG":"Also, reports say that the two are currently busy trying to maintain their territory against the newly formed ”Wizard\\".","TWN":"而且現在雙方都在牽制城市裡的新興勢力——巫師。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"지금의 규모로는 각개격파 당할 가능성이 높기 때문에 조만간 한쪽을 흡수하려고 전면전을 벌일 겁니다.","JPN":"現在の規模では各個撃破される可能性が高いので、そのうち片方を吸収しようと全面戦争をするでしょう。","ENG":"Both seem to be outnumbered, so one side will try to take over the other sometime soon.","TWN":"以現在的規模來看，很容易被逐個擊破，所以不久後他們會發動全面戰爭，試圖吞併一方。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"POLICE_NPC_CHIEF_NULL","text":{"KOREA":"놈들이 그 위저드란 놈들 때문에 서로 협력할 가능성은?","JPN":"やつらがそのウィザードという連中のせいで手を組む可能性は？","ENG":"What’s the probability of them joining forces to fight against that “Wizard\\"?","TWN":"你覺得他們會因為對付巫師而互相合作嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"원래부터 이권다툼이 심했고 심심찮게 마찰이 있어왔던 관계입니다. 지금까지의 양상으로 볼 때 그런 생각을 할 만한 브레인은 내부에 없습니다.","JPN":"元々争いが頻繁に起きていた仲です。今までの構図を踏まえると、そんなことを考えるブレーンは内部に存在しません。","ENG":"They've been at odds over territory for a long time. Furthermore, based on what has occurred thus far, neither family has anyone with the intellect to reach such an agreement.","TWN":"原本他們之間有很大的利益衝突，時不時就有摩擦。但從目前的情況來看，內部沒有人會有那樣的想法。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"POLICE_NPC_CHIEF_NULL","text":{"KOREA":"그림 좋네. 알아보느라 고생 많았어.","JPN":"結構だ。調査、ご苦労だったぞ。","ENG":"I like the sound of that. Good work, officer.","TWN":"調查得不錯，辛苦你了。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"POLICE_NPC_CHIEF_NULL","text":{"KOREA":"하지만 진압조를 움직이려면 확실한 근거가 필요해. 좀 더 조사해볼 필요가 있어.","JPN":"だが、鎮圧組を動くには確かな根拠が必要だ。もう少し調査する必要がある。","ENG":"But we need concrete evidence to send in the striking force. We need someone to keep digging.","TWN":"但是動用鎮壓隊需要確切的證據，所以還要進一步調查。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"POLICE_NPC_CHIEF_NULL","text":{"KOREA":"그쪽 관할구에서 뒷말 안 나오게 하려면 확실하게 물증 잡고 쳐야 돼.","JPN":"そちらの管轄区域で不満が出ないようにするためには、確実な物証を確保しないといけない。","ENG":"If we don’t want any backlash from that jurisdiction, we need to have irrefutable evidence.","TWN":"要想在那邊的管轄區內不留下後患，就必須得到確切的證據再動手。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"POLICE_NPC_CHIEF_NULL","text":{"KOREA":"내 말, 무슨 말인지 알겠지?","JPN":"私の話、わかるだろう？","ENG":"Do you understand my words?","TWN":"你明白我說的話吧？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"물론입니다. 그렇게 하겠습니다.","JPN":"もちろんです。そうします。","ENG":"Of course, sir. I’ll get right on it.","TWN":"明白，我立刻去辦。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PERSON_EXTRA_NULL_MINWOO","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"휴우… 시작부터 끝까지 뒤치다꺼리는 다 내 몫이구만.","JPN":"ふう……最初から最後まで後片付けは全部俺の分だな。","ENG":"Whew... Guess this one’s just me, myself, and I...","TWN":"呼…從頭到尾全都是我在做事。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PERSON_EXTRA_NULL_MINWOO","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"난 세상의 안위를 지키고 있는데 내 주말은 누가 지켜주나?","JPN":"俺は世界の平和を守ってるんだけど、俺の週末は誰が守ってくれるんだ？","ENG":"Here I am looking after the world, but who’s looking after my weekend?","TWN":"我在守護世界的安危，那誰來守護我的週末呢？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PERSON_EXTRA_NULL_MINWOO","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"……음?","JPN":"……む？","ENG":"...Mm?","TWN":"…嗯？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PERSON_EXTRA_NULL_MINWOO","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"아주 호되게 당했군.","JPN":"めちゃくちゃにやられてるな。","ENG":"Whoa... They got you good.","TWN":"下手還真狠毒。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"아직 숨은 붙어있는 것 같은데?","JPN":"まだ息はしてるみたいだぞ？","ENG":"Wait... I think he’s still breathing.","TWN":"看起來好像還有呼吸？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"으으……","JPN":"うう……","ENG":"Ugh...","TWN":"呃呃…"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"거기, 무슨 일이 있었던 겁니까?","JPN":"そこ、何かあったんですか？","ENG":"Hey! What’s going on over there?","TWN":"喂，發生了什麼事嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L28_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"넘어오지 말고 물러서세요. 일반인은 들어오시면 안 됩니다.","JPN":"近づかないで、下がってください。一般人は立ち入り禁止です。","ENG":"Please step back, sir. Authorized personnel only.","TWN":"不要靠近，請退後。非相關人員請不要靠近。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"아.","JPN":"あ。","ENG":"Oh.","TWN":"啊。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"……전 경찰청 강력계 형사, 강민우입니다.","JPN":"……俺は警察庁の捜査課刑事、マツダ・シュウイチです。","ENG":"...I’m a homicide detective, Kang Minwoo, from the police.","TWN":"…我是重案組刑警，姜民宇。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"……이쪽 관할이 아니신데, 여기까진 어쩐 일로 오셨죠?","JPN":"……こちらの管轄ではないはずなのに、どうしてここまで？","ENG":"...This isn’t your jurisdiction. What brings you here, sir?","TWN":"…這不是你的轄區，你怎麼會到這裡來？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"미안합니다. 그 부분은 대외비라서요.","JPN":"すみません。そこは極秘なんで。","ENG":"Sorry. That’s classified.","TWN":"對不起，這是機密，無可奉告。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"그나저나, 여기 무슨 싸움이라도 났던 겁니까?","JPN":"ところで、ここで何かケンカでもあったんですか？","ENG":"Anyway, what happened here?","TWN":"不過，這裡是發生了什麼火拼嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"별거 아닙니다.","JPN":"大したことじゃないです。","ENG":"It's probably nothing.","TWN":"沒什麼大不了的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"빈민가 구역에서 길거리 싸움이야 흔히 일어나는 일이죠.","JPN":"スラム街の区域で、路上でのケンカというのは珍しくもないでしょう。","ENG":"Fights and riots happen all the time in these slums.","TWN":"貧民區裡街頭鬥毆是常有的事。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯…"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"길거리 싸움 치곤 무지막지하군요. 바닥이 우그러지고, 담벼락도 깨져 있고.","JPN":"路上でのケンカにしては派手ですね。地面がへこんで、壁が割れて。","ENG":"That seems like one nasty riot to me. The floor’s all cracked, and that wall’s nearly collapsing.","TWN":"說是街頭鬥毆也未免太激烈了。地面都凹陷了，牆壁也碎裂。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"사실 이런 적이 전에도 제법 있었습니다. 동네 주민들 말로는 곰이 다녀갔다고 하죠.","JPN":"実は、今までもこんなことが結構あったんです。ここの住民曰く、クマが来たとか。","ENG":"To be frank, this has happened here before. The people here said it was a bear’s doing.","TWN":"其實以前也有過這樣的情況，鄰居都說是有熊來過。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"곰? 제가 알기로 이 근처엔 야산이 없을 텐데요?","JPN":"クマ？　俺の知ってるかぎり、この辺りに山はないはずですが？","ENG":"A bear? I’m pretty sure there isn’t a mountain close by?","TWN":"熊？據我所知，這附近沒有山啊。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"마땅한 표현이 없으니 비유를 하는 거죠.","JPN":"例えなんですよ。","ENG":"I’m guessing it’s the closest thing the people can refer to.","TWN":"可能只是隨便猜猜而已。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"현장에 용의자는 없고, 사람이 쉽게 부술 수 없는 기물을 부수는 데다가, 피해자들만 무더기로 쓰러져 있으니까요.","JPN":"現場に容疑者はいないし、人が簡単に壊せない器物を壊す上に被害者だけがいっぱい倒れていますからね。","ENG":"Whatever it is, it breaks concrete like it’s nothing, leaves a ton of injured victims, and there’s not even a single witness.","TWN":"畢竟現場沒有嫌疑人，只有滿地的受害者，跟人類無法輕易破壞的東西。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"그거… 참 골치 아프겠군요.","JPN":"それは……大変ですね。","ENG":"Whoa... That’s not good.","TWN":"真是讓人頭疼啊。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"범인은 아직 잡지 못한 겁니까?","JPN":"犯人はまだ捕まってないんですか？","ENG":"Is the culprit not captured yet?","TWN":"犯人還沒有抓到嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"크흠, 그게 말이죠.","JPN":"ゴホン、それがですね。","ENG":"Ahem... Well...","TWN":"咳咳，是這樣的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"사실 하라고만 하면 신상확보는 딱히 어렵지 않습니다.","JPN":"正直、やれと言われると身元を確保することは別に大変ではないんです。","ENG":"It’s not that difficult to find out who or what did this.","TWN":"其實只要下令，獲取身份資料並不難。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"이런 말하긴 좀 그렇지만, 공권력만으로 범죄조직의 폭주를 막는 데엔 한계가 명확합니다.","JPN":"こんなことを言うのはちょっとあれですが、公権力だけで犯罪組織の暴走を止めるにははっきりと限界があるんです。","ENG":"But the thing is... There’s a limit to what the police can do when it comes to criminal organizations and riots.","TWN":"雖然這麼說有點不好意思，但僅靠公權力來阻止犯罪組織的暴行還是比較有局限性的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"경찰청에서 야심 차게 준비한 카운터 특별 수사국도 얼마 못 가 깨진 마당이잖습니까?","JPN":"警察庁で自信満々に準備したカウンター特別捜査局もあまり長く持たなかったじゃないですか。","ENG":"Even the Police Agency's Counter Special Unit didn’t work as well as we thought, right?","TWN":"警察局雄心勃勃設立的制裁者特別搜查部，不也沒撐多久就收了，不是嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"야! 오 순경! 쓸데없는 소리 그만하고 이놈들 데려가기나 해.","JPN":"おい！　余計なこと言わないで、こいつらを連れて行け。","ENG":"Officer Oh! Stop your chit-chatting and take these guys away!","TWN":"喂！吳警官！別廢話了，快把這些傢伙帶走。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"아, 네! 알겠습니다!","JPN":"あっ、はい！　わかりました！","ENG":"Yes, sir! On it!","TWN":"啊，好的！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"미안합니다. 저희가 이쪽 주제에는 좀 민감해서요.","JPN":"すみません。私たち、こっちの話題にはちょっと敏感なんで。","ENG":"Sorry. We’re kinda on edge about that whole thing here.","TWN":"對不起，我們對這個話題有點敏感。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"아, 뭐. 이해합니다.","JPN":"あ、まあ。わかります。","ENG":"No worries. I understand.","TWN":"啊，嗯。我理解。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"POLICE_NPC_TOWN_NULL","text":{"KOREA":"더 자세한 건 여기 마을 주민들이 잘 알고 있을 겁니다.","JPN":"より詳細なことは、この村の住民がもっと詳しいはずです。","ENG":"You can talk to the residents here if you want to know more.","TWN":"更詳細的情況，這裡的居們們應該更清楚。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_NPC_TOWN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PERSON_EXTRA_POLICE_MINWOO","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"곰이라…","JPN":"クマか……","ENG":"A bear, eh?","TWN":"熊嗎…"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PERSON_EXTRA_POLICE_MINWOO","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TOWN_NPC_VISIT_1","text":{"KOREA":"글쎄요. 곰 얘기가 나오기 전까진 다들 깡패들 때문에 외출도 조심했거든요.","JPN":"さあ？　クマの話が出る前までは、みんなチンピラのせいで出かける時も気をつけてたんです。","ENG":"I’m not so sure. Before the whole bear thing, we all thought it was those criminals at work, so we feared leaving our homes.","TWN":"嗯…在熊搞破壞之前，大家都因害怕那些混混而不敢出門。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TOWN_NPC_VISIT_1","text":{"KOREA":"그런데, 곰이 나타난 뒤로는 그 녀석들도 잘 얼씬을 안 하게 됐어요.","JPN":"でも、クマが現われてから、あいつらもあまりウロウロしないようになったんですよね。","ENG":"But after the bear appeared, those thugs don’t even dare to step foot in here.","TWN":"不過，自從熊出現後，那些混混也不怎麼敢來了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TOWN_NPC_VISIT_1","text":{"KOREA":"저희 같이 장사하는 사람들 입장에선 오히려 고마운 일이죠.","JPN":"私たち商売人から見ると、むしろありがたいことです。","ENG":"For business owners like me, it’s actually been better ever since.","TWN":"對我們這些做生意的人來說，這反而是件好事呢。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"그러면, 그 곰이라는 건 마을에 도움을 주고 있다고 보시나요?","JPN":"では、あのクマという存在は村に役立ってると思ってるんですか？","ENG":"Then are you saying the bear is helping out around the village?","TWN":"那麼，你認為那隻熊是在幫助居民嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PERSON_EXTRA_POLICE_MINWOO","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TOWN_NPC_VISIT_2","text":{"KOREA":"난 별로 좋은 사람이곤 생각 안 해요.","JPN":"私は、あんまりいい人だって思ってないですよ。","ENG":"Whatever it is, it’s nothing but a thug.","TWN":"我不覺得是什麼好東西。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TOWN_NPC_VISIT_2","text":{"KOREA":"먼저 시비가 걸렸다면서 사과고 뭐고 무작정 두들겨 팬대요.","JPN":"売られたケンカは買うとか何とかで、謝られても全然構わず殴ってくるらしいんです。","ENG":"I heard it gets into fights on purpose and just beats people up!","TWN":"聽說是先被挑釁了，然後就不管三七二十一揍了對方一頓。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TOWN_NPC_VISIT_2","text":{"KOREA":"한 번은 싸우다 그랬는지 담벼락을 다 부숴 놨더라고요.","JPN":"一度は戦ってる途中でやったのか、壁を全部壊したんですよ。","ENG":"See that wall crumbling down? That’s what it leaves behind.","TWN":"有一次打架的時候，把圍牆都給拆了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TOWN_NPC_VISIT_2","text":{"KOREA":"아휴, 돈만 있었어도 진작에 이사를 갔을 텐데 원.","JPN":"もう、お金さえあればとっくに引っ越してたのにね。","ENG":"Ugh... I’d leave this place in a heartbeat if I only had the money to move...","TWN":"唉，要是有錢的話，早就搬家了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TOWN_NPC_VISIT_3","text":{"KOREA":"곰 말인가? 여기 사는 주민들 중엔 아직 피해를 봤다는 사람이 없어.","JPN":"クマかい？　ここの住民の中には、まだ被害に遭ったという人はいないよ。","ENG":"The bear? It hasn’t touched any of the residents that live here.","TWN":"你說熊嗎？沒聽說過這裡的居民受到過傷害呢。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TOWN_NPC_VISIT_3","text":{"KOREA":"동네 개들이 울기 시작하면 다들 알아서 대문을 걸어 잠그거든.","JPN":"村の犬たちが吠え始めるとみんな扉に鍵をかけるんだから。","ENG":"When the dogs start howling, we all know to get inside and lock the doors.","TWN":"一旦村裡的狗開始嚎叫，大家都會自動地鎖上大門。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"개들이… 운다고요?","JPN":"犬たちが……吠える？","ENG":"The dogs... They start howling?","TWN":"狗…嚎叫嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PERSON_EXTRA_POLICE_MINWOO","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TOWN_NPC_VISIT_3","text":{"KOREA":"그래. 마당 개들이 짖는 것도 아니고, 무슨 늑대마냥 동네 떠나가라 울어 댄다니까.","JPN":"そう。庭の犬がワンワン言うんじゃなくて、オオカミみたいに村全体に響くほどに吠えるんだって。","ENG":"Yup. They don’t bark, but start howling like wolves all throughout the neighborhood.","TWN":"是啊。不是那種普通的狗叫，而是像狼嚎一樣。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PERSON_EXTRA_POLICE_MINWOO","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};